export default function FinalResults({ results }) {
  const [user, setUser] = useState(false);
  const [saved, setSaved] = useState(false);
  const [type, setType] = useState("");
  const [articles, setArticles] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  const location = useLocation();

  useEffect(() => {
    if (localStorage.getItem("auth_token")) setUser(true);
    if (JSON.parse(localStorage.getItem("savedResults"))?.length) setSaved(true);

    let calculated =
      (results?.EI || "") +
      (results?.SN || "") +
      (results?.TF || "") +
      (results?.JP || "");

    if (!calculated || calculated.length !== 4) {
      const params = new URLSearchParams(location.search);
      calculated = params.get("type") || "";
    }

    if (!calculated || calculated.length !== 4) {
      calculated = localStorage.getItem("pendingResult") || "";
    }

    if (calculated.length === 4) {
      setType(calculated);
      localStorage.setItem("pendingResult", calculated);
    }
  }, [results, location]);

  useEffect(() => {
    if (!type) return;

    fetch(`http://localhost:5000/api/articles?type=${type}`)
      .then(res => res.json())
      .then(data => setArticles(data))
      .catch(() => setArticles([]));
  }, [type]);

  useEffect(() => {
    if (articles.length <= 2) return;

    const interval = setInterval(() => {
      setCurrentIndex(prev => (prev + 1) % articles.length);
    }, 4000);

    return () => clearInterval(interval);
  }, [articles]);

  const toggleSave = () => {
    if (!type) return;

    let savedResults = JSON.parse(localStorage.getItem("savedResults")) || [];

    if (!savedResults.includes(type)) {
      if (savedResults.length >= 3) savedResults.shift();
      savedResults.push(type);
    }

    localStorage.setItem("savedResults", JSON.stringify(savedResults));
    setSaved(true);
  };

  if (!type) return <p>Loading...</p>;

  return (
    <div className="result-layout">
      <div className="register-page">
        <div className="register-card">
          {user && (
            <img
              src={saved ? "/save1.png" : "/save.png"}
              className="save-icon-result"
              onClick={toggleSave}
              alt="save"
            />
          )}

          <img
            className="result-image"
            src={`/images/types/${type}.png`}
            alt={type}
          />

          <h2 className="register-title">{type}</h2>

          <p className="register-description">
            {typeDescriptions[type]}
          </p>

          {!user && (
            <p className="register-text">
              მონაცემების შესანახად{" "}
              <Link
                to="/register"
                className="register-link"
                onClick={() => localStorage.setItem("pendingResult", type)}
              >
                გაიარე რეგისტრაცია
              </Link>
            </p>
          )}
        </div>
      </div>

      {articles.length > 0 && (
        <div className="articles-sidebar">
          {articles.slice(currentIndex, currentIndex + 2).map(a => (
            <Link key={a.slug} to={`/articles/${a.slug}`} className="article-card">
              <b>{a.title}</b>
              <p>{a.excerpt}</p>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
